const data = $input.first().json.body || $input.first().json;

// Solo mensajes outgoing (type 1 o string 'outgoing'), no privados
const isOutgoing = data.message_type === 1 || data.message_type === 'outgoing';
if (!isOutgoing) {
  return { forward: false, reason: 'not_outgoing', type: data.message_type };
}
if (data.private === true) {
  return { forward: false, reason: 'private' };
}

// Ignorar mensajes espejados por n8n IA (ya fueron enviados a ML directamente)
if (data.content_attributes?.source === 'n8n_ai') {
  return { forward: false, reason: 'ai_mirror' };
}

const conv = data.conversation;
if (!conv) {
  return { forward: false, reason: 'no_conversation' };
}

const attrs = conv.additional_attributes || {};
if (attrs.type !== 'post-venta') {
  return { forward: false, reason: 'not_postsale', attrs_type: attrs.type };
}

// pack_id: desde additional_attributes o meta.source_id
const packId  = String(attrs.pack_id || conv.meta?.source_id || '');
// buyer_user_id: identifier del contacto del contacto almacenado al crear la conversación
const buyerId = String(conv.meta?.sender?.identifier || '');
const accountId = data.account?.id;
const text    = (data.content || '').trim();

if (!packId || !buyerId || !text) {
  return { forward: false, reason: 'missing_data', packId, buyerId, hasText: !!text };
}

return {
  forward:        true,
  pack_id:        packId,
  buyer_user_id:  buyerId,
  account_id:     accountId,
  text
};

